parameters.jsCode:
const account = $('Fetch Account Data').item.json;
const usage = $('Fetch Usage Metrics').item.json;
const calls = $('Fetch Gong Calls').item.json;

const briefing = {
  title: `QBR Briefing: ${account.name}`,
  generated_at: new Date().toISOString(),
  account_summary: {
    name: account.name,
    arr: account.arr,
    contract_start: account.contract_start,
    renewal_date: account.renewal_date,
    csm: account.csm_name,
    tier: account.tier
  },
  usage_metrics: {
    dau: usage.dau,
    mau: usage.mau,
    adoption_rate: usage.adoption_percent + '%',
    top_features: usage.top_features,
    usage_trend: usage.change_percent > 0 ? 'Growing' : 'Declining'
  },
  health_indicators: {
    nps: account.latest_nps,
    csat: account.latest_csat,
    support_tickets_90d: account.support_ticket_count,
    open_issues: account.open_issues
  },
  conversation_highlights: calls.calls?.slice(0, 5).map(c => ({
    date: c.date,
    participants: c.participants,
    summary: c.summary,
    action_items: c.action_items
  })) || [],
  expansion_opportunities: [
    usage.underutilized_features?.length > 0 ? `Underutilized features: ${usage.underutilized_features.join(', ')}` : null,
    account.additional_teams ? `${account.additional_teams} teams not yet onboarded` : null
  ].filter(Boolean),
  risk_flags: [
    usage.change_percent < -10 ? `Usage declined ${Math.abs(usage.change_percent)}%` : null,
    account.latest_nps < 7 ? `NPS is ${account.latest_nps}` : null,
    account.champion_changed ? 'Champion recently changed' : null
  ].filter(Boolean),
  talking_points: [
    'Review key wins and value delivered this quarter',
    'Discuss usage trends and adoption goals',
    'Address any open support issues',
    'Explore expansion opportunities',
    'Align on next quarter goals and success criteria'
  ]
};

return [{ json: briefing }];

parameters.text:
=📋 *QBR Briefing Ready*

*Account:* {{ $json.title }}
*ARR:* ${{ $json.account_summary.arr }}
*Health:* NPS {{ $json.health_indicators.nps }} | CSAT {{ $json.health_indicators.csat }}
*Usage Trend:* {{ $json.usage_metrics.usage_trend }}

{{ $json.risk_flags.length > 0 ? '⚠️ *Risk Flags:*\n• ' + $json.risk_flags.join('\n• ') : '✅ No risk flags' }}

📄 Doc: {{ $('Create Google Doc').item.json.documentId }}
